// // This module implements a 4-input NOR gate with one active-high input. The circuit outputs a LOW signal when all of its inputs (A, B, C) are HIGH, and the active-high input (D_H) is LOW. If D_H is HIGH, it effectively inverts the value of D_H, resulting in an additional condition for the output.
module top_module(
    Y  ,
    A  ,
    B  ,
    C  ,
    D_N
);// Module ports
    output Y  ;
    input  A  ;
    input  B  ;
    input  C  ;
    input  D_N;

    // Local signals
    wire not0_out  ;
    wire nor0_out_Y;

    //  Name  Output      Other arguments
    not not0 (not0_out  , D_N              );
    nor nor0 (nor0_out_Y, A, B, C, not0_out);
    buf buf0 (Y         , nor0_out_Y       );

endmodule
